import boto3

def create_sns_subscription(topic_arn):
    # Create an SNS client
    sns_client = boto3.client('sns')
    
    # Get user input for the subscription endpoint
    user_provided_url = input("Enter the URL for the subscription endpoint: ")
    
    try:
        # Subscribe the endpoint to the topic
        response = sns_client.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=user_provided_url
        )
        
        # Print the subscription ARN
        print(f"Subscription created with ARN: {response['SubscriptionArn']}")
    
    except Exception as e:
        print(f"An error occurred: {e}")

